sys_script_include.script:
function AppBuilderImplementBusinessProcess(vApp,business_process)
{
	var grApp = GetAppRecord(vApp);

	if (IsValidRecord(grApp) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: App could not be loaded.');
		return false;
	}

	if (grApp.scope == 'global')
	{
		LogError('AppBuilderImplementBusinessProcess: Global Apps are not supported.');
		return false;
	}

	var result = BusinessProcessValidate(business_process,true);

	if (result.valid == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Business Process is invalid:\n' + RenderValue(result));
		return false;
	}

	var strParentTable = GetStringValue(GetValue(business_process,'parent_table'));
	if (strParentTable == '')
	{
		strParentTable = 'task';
	}
	var grParentTable = GetTableRecord(strParentTable);
	if (IsValidRecord(grParentTable) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not load parent table: ' + strParentTable);
		return false;
	}


	var strScope = GetStringValue(grApp.scope);
	var strScopeSysId = GetStringValue(grApp.sys_id);
	var strProcessId = GetStringValue(GetValue(business_process,'id'));
	var strProcessName = GetStringValue(GetValue(business_process,'name'));

	var aRoles = GetValue(business_process,'_roles');

	var roleViewer = ArrayGetElementById(aRoles, 'viewer');
	if (IsObject(roleViewer) == false)
	{
		roleViewer = {
			id: 'viewer',
			description: 'A user that can view all data related to the process.'
			};
		aRoles.push(roleViewer);
	}

	var roleManager = ArrayGetElementById(aRoles, 'manager');
	if (IsObject(roleManager) == false)
	{
		roleManager = {
			id: 'manager',
			description: 'A user that can view and edit all data related to the process.'
			};
		aRoles.push(roleViewer);
	}	

	var roleAdmin = ArrayGetElementById(aRoles, 'admin');
	if (IsObject(roleAdmin) == false)
	{
		roleAdmin = {
			id: 'admin',
			description: 'A user that can view, edit and delete all data related to the process.'
			};
		aRoles.push(roleAdmin);
	}

	for (var nRole = 0; nRole < aRoles.length; nRole++)
	{
		var role = aRoles[nRole];

		var strRoleSuffix = GetStringValue(GetValue(role,'id'));
		var strRoleName = strScope + '.' + strRoleSuffix;
		var strRoleDescription = GetStringValue(GetValue(role,'description'));

		var strRoleSysId = RecordInsertOrUpdate(
			'sys_user_role',
			{
				sys_scope: strScopeSysId,
				suffix: strRoleSuffix,
				name: strRoleName
			},
			{
			},
			{
				description: strRoleDescription
			});
		if (IsValidSysId(strRoleSysId) == false)
		{
			LogError('AppBuilderImplementBusinessProcess: Could not create/update role: ' + strRoleName);
			return false;
		}
		aRoles[nRole]['sys_id'] = strRoleSysId;
	}

	var roleAdmin = ArrayGetElementById(aRoles, 'admin');
	var roleManager = ArrayGetElementById(aRoles, 'manager');
	var roleViewer = ArrayGetElementById(aRoles, 'viewer');


	var strRoleContainsSysId = RecordInsertOrUpdate(
		'sys_user_role_contains',
		{
			sys_scope: strScopeSysId,
			role: roleAdmin.sys_id,
			contains: roleManager.sys_id
		},{},{});
	if (IsValidSysId(strRoleContainsSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not add role manager to role admin.');
		return false;
	}

	for (var nRole = 0; nRole < aRoles.length; nRole++)
	{
		var role = aRoles[nRole];
		var strId = role['id'];
		if (strId != 'admin' && strId != 'viewer')
		{
			var strRoleContainsSysId = RecordInsertOrUpdate(
				'sys_user_role_contains',
				{
					sys_scope: strScopeSysId,
					role: role.sys_id,
					contains: roleViewer.sys_id
				},{},{});
			if (IsValidSysId(strRoleContainsSysId) == false)
			{
				LogError('AppBuilderImplementBusinessProcess: Could not add role viewer to role '+strId+'.');
				return false;
			}
		}
	}


	var strTableName = strScope + '_' + strProcessId;
	var strTableLabel = strProcessName;


	var strTableSysId = RecordInsertOrUpdate(
		'sys_db_object',
		{
			sys_scope: strScopeSysId,
			name: strTableName
		},
		{
			super_class: grParentTable.sys_id
		},
		{
			label: strTableLabel,
			configuration_access: true,
			create_access: true,
			update_access: true,
			delete_access: true
		});
	if (IsValidSysId(strTableSysId) == false)
	{
		LogError('AppBuilderImplementBusinessProcess: Could not create/update table: ' + strTableName);
		return false;
	}

	return true;
}
